mapper.select:
      
      SELECT * FROM (
         SELECT ROWNUM AS RNUM, list.* FROM (
            SELECT * FROM bnc_notice notice 
      
	      
	         
	         WHERE notice.${searchType} like '%'||#{searchKeyword}||'%'
	         
	      
	      order by notc_number DESC
      
         ) list
      )
      
      
      
      WHERE RNUM > #{startRowNumber} AND RNUM <= #{endRowNumber}

mapper.update:
update bnc_notice set 
	notc_title = #{notc_title}, 
	notc_udate = TO_CHAR(sysdate, 'YYYYMMDDHHmmss'), 
	notc_contents = #{notc_contents}
	WHERE notc_number = #{notc_number}
